create table if not exists exams(id uuid primary key default gen_random_uuid(),title text not null,description text,course_id uuid references courses(id),duration_minutes int default 20,pass_score int default 60,published boolean default false,created_at timestamptz default now()); create table if not exists questions(id uuid primary key default gen_random_uuid(),exam_id uuid references exams(id) on delete cascade,type text not null,text text not null,options jsonb not null default '[]',answer text not null,score int default 5,explanation text,position int default 0); create table if not exists exam_attempts(id uuid primary key default gen_random_uuid(),exam_id uuid references exams(id),user_id uuid references profiles(id),score int default 0,passed boolean default false,started_at timestamptz default now(),submitted_at timestamptz); create table if not exists exam_answers(id uuid primary key default gen_random_uuid(),attempt_id uuid references exam_attempts(id) on delete cascade,question_id uuid references questions(id),answer text,is_correct boolean default false);